import React from 'react';

const Home = () => {
  return (
    <section id="home" style={styles.section}>
      <h2>Hi, I'm [Your Name]</h2>
      <p>I'm a developer specializing in React, Express, and AI/ML.</p>
    </section>
  );
};

const styles = {
  section: {
    padding: '4rem 2rem', textAlign: 'center', backgroundColor: '#f4f4f4'
  }
};

export default Home;
